class Solution:
    def minSwaps(self, s: str) -> int:
        imbalance = 0
        swaps = 0
        for bracket in s:
            if bracket == '[':
                imbalance -= 1
            else:
                imbalance += 1
            if imbalance > 0:
                swaps += 1
                imbalance = 0
        return swaps
```

